def butterfly(n):
    res = []
    for i in range(1, n + 1):
        stars = '*' * i
        spaces = ' ' * (2 * (n - i))
        res.append(stars + spaces + stars)
    return '\n'.join(res)

if __name__ == "__main__":
    print(butterfly(3))
